using Microsoft.AspNetCore.Mvc;

public class ReportController : Controller
{
    // MIGRATION: btnExport_Click → action method returning IActionResult.
    //
    // What changed:
    //  • Response.Clear(), Response.Write(), Response.End() are all gone.
    //  • Return a FileContentResult instead — the framework handles the
    //    response lifecycle. No thread is aborted; the method simply returns.
    //  • GenerateReport() should return a string or byte[]; we encode to UTF-8.

    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();
        var bytes = System.Text.Encoding.UTF8.GetBytes(data);

        return File(bytes, "text/csv", "report.csv");
        // Framework sets Content-Disposition: attachment automatically
        // when the fileDownloadName parameter is provided.
    }

    // MIGRATION: btnRedirect_Click → action method returning IActionResult.
    //
    // What changed:
    //  • Response.Redirect(url, true) → return RedirectResult.
    //    Returning ends the method naturally — no Thread.Abort needed.
    //  • The catch (ThreadAbortException) block is deleted entirely.
    //    It existed only because Response.Redirect(url, true) threw
    //    ThreadAbortException. With IActionResult returns, no exception
    //    is thrown on redirect.
    //  • Each code path returns an IActionResult — the framework writes
    //    the response after the method returns.

    [HttpPost]
    public IActionResult Redirect()
    {
        if (User.Identity?.IsAuthenticated != true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // No catch (ThreadAbortException) — it no longer exists.
        // Response.Redirect no longer aborts the thread; we just return.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => throw new NotImplementedException();
    private void ProcessRequest() => throw new NotImplementedException();
    private void LogError(Exception ex) => throw new NotImplementedException();
}


// =============================================================================
// PITFALLS & KEY DIFFERENCES
// =============================================================================
//
// 1. Response.End() does NOT exist in ASP.NET Core.
//    ───────────────────────────────────────────────
//    Don't try to call HttpResponse.CompleteAsync() as a substitute for
//    Response.End(). Instead, return an IActionResult (FileResult,
//    ContentResult, etc.) and let the framework manage the response.
//
// 2. Response.Redirect(url, true) is gone — the 'true' (endResponse)
//    parameter has no equivalent.
//    ───────────────────────────────────────────────
//    In ASP.NET Core, Response.Redirect(url) exists but does NOT end
//    execution. Code after it CONTINUES to run, which can cause double-
//    response bugs. Always prefer returning RedirectResult / Redirect()
//    from the action method instead.
//
//    ⚠️ DANGEROUS ANTI-PATTERN in ASP.NET Core:
//
//        HttpContext.Response.Redirect("/login");
//        // Code here STILL RUNS — unlike the old Response.Redirect(url, true)
//        ProcessRequest(); // This will execute!
//
//    ✅ CORRECT — return exits the method:
//
//        return Redirect("/login");
//
// 3. catch (ThreadAbortException) blocks must be removed.
//    ───────────────────────────────────────────────
//    ThreadAbortException no longer gets thrown. If you leave catch blocks
//    for it, they are dead code. Worse, if you restructured your error
//    handling around them, the control flow is now wrong.
//
//    Review every catch (ThreadAbortException) block: if it had cleanup
//    logic, move that logic to a finally block or handle it at the
//    appropriate level.
//
// 4. WebForms event handlers → MVC action methods.
//    ───────────────────────────────────────────────
//    WebForms button click handlers (void return, EventArgs parameter)
//    become action methods returning IActionResult. You lose the page
//    lifecycle (Page_Load, IsPostBack, ViewState). Plan for a full
//    rewrite of the page interaction model, not just a Thread.Abort fix.
//
// 5. Use HttpContext.RequestAborted for long-running work.
//    ───────────────────────────────────────────────
//    If GenerateReport() is slow, pass the cancellation token so the
//    work stops if the client disconnects:
//
//        var data = await GenerateReportAsync(HttpContext.RequestAborted);
//
//    This is the cooperative cancellation replacement for the old pattern
//    where Thread.Abort would kill a request thread on client disconnect.
//
// 6. Null-check User.Identity in ASP.NET Core.
//    ───────────────────────────────────────────────
//    User.Identity can be null if no authentication middleware is
//    configured. Use User.Identity?.IsAuthenticated != true instead of
//    !User.Identity.IsAuthenticated to avoid NullReferenceException.
//    In practice, prefer the [Authorize] attribute for auth checks.
//
